    collection, err := domain.NewCollection(userID, name)
    if err != nil {
        return nil, mapDomainError(err)
    }
    if err := uc.collectionRepo.Create(ctx, collection); err != nil {
        return nil, apperr.InternalServerError("collection.create_error", err)
    }
    for _, vid := range vocabIDs {
        if err := uc.collectionItemRepo.Add(ctx, collection.ID, vid); err != nil {
            return nil, apperr.InternalServerError("collection.add_item_error", err)
        }
    }
    return toCollectionResponse(collection), nil
}
