func (h *CollectionHandler) UpdateCollection(c *gin.Context) {
    userID := c.MustGet("user_id").(domain.UserID)
    collectionID, ok := parseCollectionID(c)
    if !ok {
        return
    }
    var req dto.UpdateCollectionRequest
    if err := c.ShouldBindJSON(&req); err != nil {
        response.ValidationError(c, err)
        return
    }
    // Check if collection exists and belongs to user
    existing, err := h.collectionRepo.GetByID(c.Request.Context(), collectionID)
    if err != nil {
        response.HandleError(c, apperr.InternalServerError("common.internal_error", err))
        return
    }
    if existing == nil || existing.UserID != userID {
        response.NotFound(c, "collection.not_found")
        return
    }
    // Update name if changed
    if req.Name != "" && req.Name != existing.Name {
        existing.Name = strings.TrimSpace(req.Name)
    }
    res, err := h.useCase.UpdateCollection(c.Request.Context(), existing)
    if err != nil {
        response.HandleError(c, err)
        return
    }
    response.Success(c, http.StatusOK, res)
}
