func (uc *TopicUseCase) ListTopicsWithVocabCount(ctx context.Context) ([]dto.TopicWithCount, error) {
    topics, err := uc.topicRepo.ListAll(ctx)
    if err != nil {
        return nil, apperr.InternalServerError("topic.fetch_error", err)
    }
    result := make([]dto.TopicWithCount, 0, len(topics))
    for _, t := range topics {
        count, err := uc.vocabRepo.CountByTopicID(ctx, t.ID)
        if err != nil {
            return nil, apperr.InternalServerError("topic.count_error", err)
        }
        result = append(result, dto.TopicWithCount{Topic: toTopicDTO(t), VocabCount: count})
    }
    return result, nil
}
